-- =====================================================
-- INSERÇÃO DE DADOS DE PERFORMANCE - KPIs das planilhas
-- Total: 357 registros
-- Jul-Dez/2024 + Jan-Fev/2025
-- =====================================================

DO $$
DECLARE v_user_id UUID;
BEGIN
  -- Pega o primeiro usuário (ajuste se precisar de outro)
  SELECT id INTO v_user_id FROM auth.users ORDER BY created_at LIMIT 1;

  -- Remove dados existentes do mesmo período para evitar duplicatas
  DELETE FROM public.publicidade_dados
  WHERE month IN ('Julho','Agosto','Setembro','Outubro','Novembro','Dezembro','Janeiro','Fevereiro')
  AND year IN (2024, 2025);


END $$;